from dataclasses import dataclass


@dataclass
class Item:
    name: str
    unit_price: float
    qty: int

    # BUG: decorator missing — price becomes method, but caller treats it as attribute
    def price(self):
        return self.unit_price * self.qty


def compute_total(items):
    # typo: iterates over integers not items
    return sum(item.price() for item in items)


def main():
    items = [Item('a', 2.5, 3).qty, Item('b', 1.0, 10).qty]
    total = compute_total(items)
    print('total:', total)


if __name__ == '__main__':
    main()
